// Parse Kaggle Competition/Hackathon Launch email
// Verified against real emails:
//   Competition: "Competition Launch: ARC Prize 2026" — uses "Entry Deadline:"
//   Hackathon:   "Hackathon Launch: The MedGemma Impact Challenge" — uses "Final Submission:"
const subject = $input.first().json.subject || '';
const body = $input.first().json.text || '';
const html = $input.first().json.html || '';

// Detect event type from subject
let eventType = 'competition';
if (subject.match(/Hackathon Launch/i)) {
  eventType = 'hackathon';
}

// Extract name from subject — format: "Competition Launch: ARC Prize 2026"
// Note: name can contain colons (e.g. "Measuring Progress Toward AGI: Cognitive Abilities")
const nameMatch = subject.match(/(?:Competition|Hackathon)\s+Launch:\s*(.+)/i);
const competitionName = nameMatch ? nameMatch[1].trim() : subject;

// Strip HTML tags for text search
const searchText = body || html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ');

// Extract deadline
// Competition emails use "Entry Deadline:", Hackathon emails use "Final Submission:"
const deadlinePatterns = [
  /Entry Deadline[:\s]*([A-Za-z]+\s+\d{1,2},?\s+\d{4})/i,
  /Final Submission[:\s]*([A-Za-z]+\s+\d{1,2},?\s+\d{4})/i,
  /Submission Deadline[:\s]*([A-Za-z]+\s+\d{1,2},?\s+\d{4})/i,
  /deadline[:\s]+([A-Za-z]+\s+\d{1,2},?\s+\d{4})/i,
  /ends?\s+on\s+([A-Za-z]+\s+\d{1,2},?\s+\d{4})/i
];
let deadline = 'Unknown';
for (const pattern of deadlinePatterns) {
  const match = searchText.match(pattern);
  if (match) {
    deadline = match[1].trim();
    break;
  }
}

// Extract prize — format: "Total Prizes:" then "$2,000,000" or "$100,000"
const prizeMatch = searchText.match(/Total Prizes?[:\s]*(\$[\d,\.]+)/i);
const prize = prizeMatch ? prizeMatch[1].trim() : 'Not specified';

// Extract Kaggle URL from HTML (links in <a href="...">)
const urlPatterns = [
  /https:\/\/www\.kaggle\.com\/competitions\/[^\s\"'<>]+/i,
  /https:\/\/www\.kaggle\.com\/c\/[^\s\"'<>]+/i
];
let url = 'https://www.kaggle.com/competitions';
for (const pattern of urlPatterns) {
  const match = html.match(pattern) || body.match(pattern);
  if (match) {
    url = match[0];
    break;
  }
}

// Infer track from email content (Kaggle emails have no explicit track field)
// Keywords are matched against subject + body to classify the competition
const content = (subject + ' ' + searchText).toLowerCase();
const trackKeywords = [
  { track: 'AI/ML', keywords: ['machine learning', 'deep learning', 'neural network', 'ai model', 'llm', 'nlp', 'computer vision', 'reinforcement learning', 'agi', 'generalization', 'reasoning'] },
  { track: 'Data Science', keywords: ['data science', 'tabular', 'regression', 'classification', 'analytics', 'feature engineering', 'eda'] },
  { track: 'Healthcare', keywords: ['medical', 'health', 'clinical', 'patient', 'diagnostics', 'biomedical', 'medgemma'] },
  { track: 'Environment', keywords: ['climate', 'wildlife', 'biodiversity', 'species', 'bird', 'ecology', 'environmental'] }
];
let track = 'Other';
for (const entry of trackKeywords) {
  if (entry.keywords.some(kw => content.includes(kw))) {
    track = entry.track;
    break;
  }
}

return [{
  json: {
    event_type: eventType,
    competition_name: competitionName,
    deadline: deadline,
    prize: prize,
    track: track,
    url: url,
    raw_subject: subject
  }
}];

// Match parsed email data against rules (supports event_type: competition/hackathon)
const emailData = $('Parse Email').first().json;
const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
const rulesFile = JSON.parse(binaryData.toString());
const rules = rulesFile.rules;

let matchedRule = null;

for (const rule of rules) {
  // Check event_type match first
  const ruleEventType = rule.match.event_type || '*';
  if (ruleEventType !== '*' && ruleEventType !== emailData.event_type) {
    continue;
  }

  const tracks = rule.match.track;

  // Check track match
  let trackMatch = false;
  if (tracks.includes('*')) {
    trackMatch = true;
  } else {
    const emailTrack = emailData.track.toLowerCase();
    trackMatch = tracks.some(t => emailTrack.includes(t.toLowerCase()));
  }

  if (!trackMatch) continue;

  // Check keyword match in competition name
  let keywordMatch = true;
  if (rule.match.keyword_in_name && rule.match.keyword_in_name.length > 0) {
    const name = emailData.competition_name.toLowerCase();
    keywordMatch = rule.match.keyword_in_name.some(k => name.includes(k.toLowerCase()));
  }

  if (keywordMatch) {
    matchedRule = rule;
    break;
  }
}

if (!matchedRule) {
  matchedRule = {
    id: 'default',
    name: 'Default Action',
    actions: [{ type: rulesFile.default_action, config: {} }]
  };
}

// Merge email data with matched rule actions
const results = matchedRule.actions.map(action => {
  const config = { ...action.config };
  if (!config.chat_id) {
    config.chat_id = '';
  }
  return {
    json: {
      ...emailData,
      action_type: action.type,
      action_config: config,
      matched_rule: matchedRule.name
    }
  };
});

return results;

// Log action for unhandled types
console.log('Unhandled action type:', $json.action_type);
console.log('Competition:', $json.competition_name);
console.log('Matched rule:', $json.matched_rule);
return [$input.first()];

// Read telegram config from binary data
const configBinary = await this.helpers.getBinaryDataBuffer(0, 'data');
const config = JSON.parse(configBinary.toString());
const defaultChatId = String(config.default_chat_id || '');

// Get the current item data from Match Rule
const item = $('Match Rule').first().json;

// Use per-rule chat_id if set, otherwise use default from config
const chatId = item.action_config.chat_id || defaultChatId;

return [{
  json: {
    ...item,
    action_config: {
      ...item.action_config,
      chat_id: chatId
    }
  }
}];
